經營小麵攤且平均月營業額新臺幣 22 萬元，領有免開統一發票證明
之獨資商號負責人。（9 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "33fb77e0762a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "106", "s": "0416", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "破產法與消費者債務清理條例", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官法律事務組"}'::jsonb, NULL),
  ('judicial-388a63c0-moex-00022', 'judicial-388a63c0', 'judicial-388a63c0-moex-113-8d1d3a67', 'sub-judicial-388a63c0-01', NULL, 'essay', '審判中，檢察官提出被告甲在警詢時的自白筆錄及錄音檔案作為證據之
一。在調查證據時，甲爭執筆錄的內容與當日自己的陳述有出入，法官
當庭播放警詢時的錄音檔案，不料發現其品質極差，完全無法分辨是否
為甲的聲音或是其內容為何。試問自白筆錄有無證據能力？請詳述理由
說明。（35 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "2aebff7e989b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "106", "s": "0510", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官法律事務組"}'::jsonb, NULL),
  ('judicial-388a63c0-moex-00023', 'judicial-388a63c0', 'judicial-388a63c0-moex-113-8d1d3a67', 'sub-judicial-388a63c0-01', NULL, 'essay', '檢察官在偵查結束後，就涉犯殺人未遂罪的嫌疑人甲提起公訴。在審判
中，甲未選任律師為自己辯護，法院也沒有為其指定辯護人。法院審判
後，認檢察官所提出的證據未能證明甲犯罪，諭知無罪判決。檢察官不
服，提起上訴，主張之一是法院未為甲指定辯護人，訴訟程序違法。試
問檢察官的主張是否有理由？請附理由詳細說明。（35分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "2aebff7e989b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "106", "s": "0510", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官法律事務組"}'::jsonb, NULL),
  ('judicial-388a63c0-moex-00024', 'judicial-388a63c0', 'judicial-388a63c0-moex-113-8d1d3a67', 'sub-judicial-388a63c0-01', NULL, 'essay', '警察甲在巡邏時，發現棄置在路邊的機車為先前被害人報案失竊之物，
於是陳報檢察官。檢察官命甲予以扣押。在審判中，檢察官提出該贓車
作為證據，證明被告乙的犯罪事實。試問檢察官命警察扣押的機車有無
證據能力？（30分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "2aebff7e989b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "106", "s": "0510", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官法律事務組"}'::jsonb, NULL),
  ('judicial-388a63c0-moex-00025', 'judicial-388a63c0', 'judicial-388a63c0-moex-113-916530c6', 'sub-judicial-388a63c0-02', NULL, 'essay', '船長甲駕駛我國籍遠洋漁船至公海上作業，船員A因操作起網機致漁網
嚴重破損而遭甲責罵，甲也發現值班中的 A在船艙內喝酒，經勸導而起
爭執，甲怒斥 A：「下次看見喝酒，殺了餵魚！」，乙則在一旁竊喜。某
日，不懷好意的乙趁甲午睡時將空酒瓶放在桌上，製造 A喝酒的假象，
甲睡醒後認為 A 又於值班時喝酒，當場怒不可遏而起殺機，A 見甲持
槍，遂抱浮球躍入海中，甲見狀駕船衝撞 A，欲置其於死地，但湧起的
波浪卻將浮球沖開，致無法直接撞及。甲知道附近沒有其他船隻，A無
獲救希望，仍駕船離去，A死於海上。試問甲、乙的刑責為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:25+00:00", "source_pdf_sha1": "bfe73cacc463", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "106", "s": "0502", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官法律事務組"}'::jsonb, NULL),
  ('judicial-388a63c0-moex-00026', 'judicial-388a63c0', 'judicial-388a63c0-moex-113-916530c6', 'sub-judicial-388a63c0-02', NULL, 'essay', 'A女將賓士車違停在路邊，想到後面的土地公廟拜拜即回來，讓八歲的
兒子 B留在車上等待，在汽車沒有熄火與上鎖下就下車。甲此時路過觀
察，發現車門可打開，立刻坐上車開走，才發現坐在後座的 B專心低頭
滑手機，竟以活埋恐嚇 B配合，此時心想不如撈一筆，遂將車開到產業
道路，逼 B說出父母的手機號碼，撥打電話給 A，要 A準備新臺幣（下
同）500 萬現金並依指示放在某定點，否則準備收屍。A 報警，在家屬
要求甲降低金額時，承辦的警員乙財迷心竅，打電話給 A且訛稱歹徒，
表示願意將金額降為 100 萬元，告知更改置放現金的地點。在家屬未交
付任何現金前，甲獲知警察已介入調查，於是將B載至人煙稀少處再趕
下車，B安全回到家。依刑法規定，甲、乙的刑責為何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:25+00:00", "source_pdf_sha1": "bfe73cacc463", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "106", "s": "0502", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官法律事務組"}'::jsonb, NULL),
  ('judicial-388a63c0-moex-00027', 'judicial-388a63c0', 'judicial-388a63c0-moex-113-916530c6', 'sub-judicial-388a63c0-02', NULL, 'essay', '甲是賽車迷，所屬的自用小客車因交通違規遭吊扣，看見 A於社交軟體
張貼製作假車牌之廣告，即透過通訊軟體與 A聯繫，以新臺幣 1萬 2 千
元之代價要求 A偽造兩面其指定的車牌號碼，再將偽造車牌懸掛於上述
自用小客車之車身。某日，甲邀乙等共四人於凌晨開車競速，沿路燃放
煙火取樂，並以前後或併排或逆向飆車之方法，超速競駛於供公眾往來
通行之道路上，乙因為車速過快失控自撞電線桿，猛烈撞擊導致車體零
件散落一地，終因傷重不治死亡。試問甲的刑責為何？（25分）
41020', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:25+00:00", "source_pdf_sha1": "bfe73cacc463", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "106", "s": "0502", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官法律事務組"}'::jsonb, NULL),
  ('judicial-388a63c0-moex-00028', 'judicial-388a63c0', 'judicial-388a63c0-moex-113-916530c6', 'sub-judicial-388a63c0-02', NULL, 'essay', '甲於晚上與友人喝酒餐聚，回家後倒頭大睡，睡了 6 小時後起床聽聞 A
想搭臺鐵北上，自告奮勇稱願意開車搭載 A前往車站，途中超車駛入對
向車道，卻不慎擦撞迎面而來的騎士 B女，B人車倒地。甲下車看見 B
僅受皮肉傷且能自行站立扶起機車，因趕著送 A到車站，即匆忙開車離
開，回到家時看見警察已在門口等候，警察對甲實施酒測，測得吐氣酒
精濃度值為每公升 0.28 毫克。數日後，B因腦部受創出現植物人狀態，
甲在庭上辯稱：事發前晚有喝酒，但睡醒後沒有任何宿醉感或頭昏現象，
且當下僅看見 B受輕傷。試問甲的刑責為何？甲駕駛的車輛是否得沒收
之？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:25+00:00", "source_pdf_sha1": "bfe73cacc463", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "106", "s": "0502", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官法律事務組"}'::jsonb, NULL),
  ('judicial-388a63c0-moex-00029', 'judicial-388a63c0', 'judicial-388a63c0-moex-113-38f6539c', 'sub-judicial-388a63c0-03', NULL, 'essay', '甲與乙原係好友，甲自民國（下同）106 年起長期向乙借貸金錢創業，
並簽有借據，累積至 113 年 1月總借款結算後已達新臺幣350萬元，乙
因結婚急需用錢乃向甲請求返還，雙方於是口頭約定 113 年 4 月1 日清
償全部借款。詎屆期甲因創業失敗仍未清償，乙乃向甲發出存證信函催
告，甲則回函斷然拒絕清償並否認有債務，並於回函中聲稱此款項實則
為乙為投資甲創業所為之投資行為，並非借款，投資本即有賺有賠，不
能因創業失敗即欲追回款項。乙催告遭拒後，為保全債權，於起訴前乃
提出 106 年甲簽署之借據及 113 年之催告存證信函及甲拒絕履行之回
函，向新北地方法院聲請假扣押，並陳明若假扣押釋明有不足，願供擔
保以補充之，經地方法院以乙僅釋明債權之存在，但完全未釋明假扣押
之原因而駁回其假扣押之聲請，乙不服，提出異議主張其提出之存證信
函即為假扣押原因之釋明。請問乙之異議是否有理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:25+00:00", "source_pdf_sha1": "8ef0d807746a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "106", "s": "0413", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法與非訟事件法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官法律事務組"}'::jsonb, NULL),
  ('judicial-388a63c0-moex-00030', 'judicial-388a63c0', 'judicial-388a63c0-moex-113-38f6539c', 'sub-judicial-388a63c0-03', NULL, 'essay', '強制執行之基本價值「比例原則」、「人道原則」、「效率原則」為何？請
引用強制執行法條文說明之。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:25+00:00", "source_pdf_sha1": "8ef0d807746a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "106", "s": "0413", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法與非訟事件法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "司法事務官法律事務組"}'::jsonb, NULL)
